    { name: { en: 'corn tortillas', ro: 'Tortillas de porumb', ru: 'Кукурузные тортильи', es: 'Tortillas de maiz' }, measure: '6' },
    { name: { en: 'chicken breasts', ro: 'Piepturi de pui', ru: 'Куриные грудки', es: 'Pechugas de pollo' }, measure: '2' }
