    { name: { en: 'Coriander', ro: 'Coriandru', ru: 'Кориандр', es: 'Cilantro' }, measure: '1 teaspoon' },
    { name: { en: 'Cardamom', ro: 'Cardamom', ru: 'Кардамон', es: 'Cardamomo' }, measure: '½ tbsp' },
    { name: { en: 'Cloves', ro: 'Cuisoare', ru: 'Гвоздика', es: 'Clavos de olor' }, measure: '¼ teaspoon' },
    { name: { en: 'Cinnamon', ro: 'Scortisoara', ru: 'Корица', es: 'Canela' }, measure: '1/2 tsp' },
    { name: { en: 'Pepper', ro: 'Piper', ru: 'Перец', es: 'Pimienta' }, measure: '1 tsp' },
    { name: { en: 'Bay Leaf', ro: 'Frunza de dafin', ru: 'Лавровый лист', es: 'Hoja de laurel' }, measure: '2' }
