    { name: { en: 'Olive Oil', ro: 'Ulei de masline', ru: 'Оливковое масло', es: 'Aceite de oliva' }, measure: '3 tablespoons' },
    { name: { en: 'Greek Yogurt', ro: 'Iaurt grecesc', ru: 'Греческий йогурт', es: 'Yogur griego' }, measure: '1 cup' },
    { name: { en: 'Garlic', ro: 'Usturoi', ru: 'Чеснок', es: 'Ajo' }, measure: '1 clove peeled crushed' },
    { name: { en: 'Cumin', ro: 'Chimion', ru: 'Кумин', es: 'Comino' }, measure: '1 tsp' },
    { name: { en: 'Lemon Juice', ro: 'Suc de lamaie', ru: 'Лимонный сок', es: 'Jugo de limon' }, measure: 'Splash' }
