    { name: { en: 'Butter', ro: 'Unt', ru: 'Сливочное масло', es: 'Mantequilla' }, measure: '25g' },
    { name: { en: 'Icing Sugar', ro: 'Zahar pudra', ru: 'Сахарная пудра', es: 'Azucar glass' }, measure: '100g' },
    { name: { en: 'Desiccated Coconut', ro: 'Nuca de cocos rasa', ru: 'Кокосовая стружка', es: 'Coco rallado' }, measure: '100g' }
